  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState, useEffect } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { buildAgentsUrl, type AgentListItem } from "../../hooks/use-agents";
 13→import { useWorkspaceState } from "../../stores/workspace-state";
 14→import { usePublicConfig } from "../../hooks/use-public-config";
 15→import { AgentSessionPanel } from "./AgentSessionPanel";
 16→import { Button } from "../ui/button";
 17→import { Input } from "../ui/input";
 18→import { Badge } from "../ui/badge";
 19→import {
 20→  Select,
 21→  SelectContent,
 22→  SelectItem,
 23→  SelectTrigger,
 24→  SelectValue,
 25→} from "../ui/select";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Pure core: view derivation
 29→// ---------------------------------------------------------------------------
 30→
 31→const ASSIGNABLE_STATUSES = new Set(["open", "ready", "todo"]);
 32→
 33→export type AgentStatusViewHidden = { variant: "hidden" };
 34→export type AgentStatusViewAssign = { variant: "assign" };
 35→export type AgentStatusViewActive = {
 36→  variant: "active";
 37→  agentSessionId: string;
 38→  orchestratorStatus: string;
 39→  filesChangedCount: number;
 40→  streamId: string;
 41→  startedAt: string;
 42→};
 43→
 44→export type AgentStatusView =
 45→  | AgentStatusViewHidden
 46→  | AgentStatusViewAssign
 47→  | AgentStatusViewActive;
 48→
 49→export type DeriveAgentStatusInput = {
 50→  entityKind: string;
 51→  entityStatus: string;
 52→  agentSession?: AgentSessionSummary;
 53→};
 54→
 55→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 56→  if (input.entityKind !== "task") {
 57→    return { variant: "hidden" };
 58→  }
 59→
 60→  if (input.agentSession) {
 61→    return {
 62→      variant: "active",
 63→      agentSessionId: input.agentSession.agentSessionId,
 64→      orchestratorStatus: input.agentSession.orchestratorStatus,
 65→      filesChangedCount: input.agentSession.filesChangedCount,
 66→      streamId: input.agentSession.streamId,
 67→      startedAt: input.agentSession.startedAt,
 68→    };
 69→  }
 70→
 71→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 72→    return { variant: "assign" };
 73→  }
 74→
 75→  return { variant: "hidden" };
 76→}
 77→
 78→// ---------------------------------------------------------------------------
 79→// Repo path banner visibility
 80→// ---------------------------------------------------------------------------
 81→
 82→export function shouldShowRepoPathBanner(input: {
 83→  worktreeManagerEnabled: boolean;
 84→  repoPath: string | undefined;
 85→}): boolean {
 86→  if (!input.worktreeManagerEnabled) return false;
 87→  return input.repoPath === undefined;
 88→}
 89→
 90→// ---------------------------------------------------------------------------
 91→// Status badge display
 92→// ---------------------------------------------------------------------------
 93→
 94→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 95→  spawning: "Spawning",
 96→  active: "Working",
 97→  idle: "Idle",
 98→  completed: "Completed",
 99→  aborted: "Aborted",
100→  error: "Error",
101→};
102→
103→const STATUS_VARIANTS: Record<AgentSessionStatus, "default" | "secondary" | "destructive" | "outline"> = {
104→  spawning: "outline",
105→  active: "default",
106→  idle: "secondary",
107→  completed: "secondary",
108→  aborted: "destructive",
109→  error: "destructive",
110→};
111→
112→function statusLabel(status: AgentSessionStatus): string {
113→  return STATUS_LABELS[status];
114→}
115→
116→// ---------------------------------------------------------------------------
117→// Pure core: assignable agent filtering
118→// ---------------------------------------------------------------------------
119→
120→export function filterAssignableAgents(agents: AgentListItem[]): AgentListItem[] {
121→  return agents.filter((agent) => agent.runtime !== "brain");
122→}
123→
124→export function deriveInitialSelectedAgent(assignableAgents: AgentListItem[]): string | undefined {
125→  if (assignableAgents.length === 1) return assignableAgents[0].id;
126→  return undefined;
127→}
128→
129→// ---------------------------------------------------------------------------
130→// Component
131→// ---------------------------------------------------------------------------
132→
133→export function AgentStatusSection({
134→  entityId,
135→  workspaceId,
136→  entityKind,
137→  entityStatus,
138→  agentSession,
139→}: {
140→  entityId: string;
141→  workspaceId: string;
142→  entityKind: EntityKind;
143→  entityStatus: string;
144→  agentSession?: AgentSessionSummary;
145→}) {
146→  const repoPath = useWorkspaceState((s) => s.repoPath);
147→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
148→  const config = usePublicConfig();
149→  const [assigning, setAssigning] = useState(false);
150→  const [assignError, setAssignError] = useState<string | undefined>();
151→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
152→  const [repoPathInput, setRepoPathInput] = useState("");
153→  const [settingRepoPath, setSettingRepoPath] = useState(false);
154→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
155→  const [assignableAgents, setAssignableAgents] = useState<AgentListItem[]>([]);
156→  const [agentsLoading, setAgentsLoading] = useState(false);
157→  const [selectedAgentId, setSelectedAgentId] = useState<string | undefined>();
158→
159→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
160→
161→  useEffect(() => {
162→    if (initialView.variant !== "assign") return;
163→    let cancelled = false;
164→    setAgentsLoading(true);
165→    fetch(buildAgentsUrl(workspaceId))
166→      .then((res) => (res.ok ? res.json() : Promise.reject(new Error("Failed to fetch agents"))))
167→      .then((data: { agents: AgentListItem[] }) => {
168→        if (cancelled) return;
169→        const filtered = filterAssignableAgents(data.agents);
170→        setAssignableAgents(filtered);
171→        setSelectedAgentId(deriveInitialSelectedAgent(filtered));
172→      })
173→      .catch(() => {
174→        if (!cancelled) setAssignableAgents([]);
175→      })
176→      .finally(() => { if (!cancelled) setAgentsLoading(false); });
177→    return () => { cancelled = true; };
178→  }, [initialView.variant, workspaceId]);
179→
180→  const streamUrl = assignResult?.streamUrl ?? (
181→    initialView.variant === "active"
182→      ? `/api/orchestrator/${encodeURIComponent(workspaceId)}/sessions/${encodeURIComponent(initialView.agentSessionId)}/stream`
183→      : undefined
184→  );
185→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
186→
187→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
188→
189→  const hasActiveStream = streamUrl !== undefined;
190→
191→  if (initialView.variant === "hidden" && !hasActiveStream) {
192→    return undefined;
193→  }
194→
195→  async function handleAssign() {
196→    if (assigning) return;
197→    setAssigning(true);
198→    setAssignError(undefined);
199→    try {
200→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
201→      const result = await assignAgent(workspaceId, rawTaskId, selectedAgentId);
202→      setAssignResult(result);
203→    } catch (err) {
204→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
205→    } finally {
206→      setAssigning(false);
207→    }
208→  }
209→
210→  if (hasActiveStream) {
211→    const displayStatus = sessionState.status;
212→    const displayFiles = initialView.variant === "active"
213→      ? initialView.filesChangedCount + sessionState.filesChanged
214→      : sessionState.filesChanged;
215→
216→    const currentSessionId = assignResult?.agentSessionId
217→      ?? (initialView.variant === "active" ? initialView.agentSessionId : "");
218→
219→    return (
220→      <div className="flex flex-col gap-2 px-4">
221→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
222→        <div className="flex items-center gap-2">
223→          <Badge variant={STATUS_VARIANTS[displayStatus]} data-testid="agent-status-badge">
224→            {statusLabel(displayStatus)}
225→          </Badge>
226→          {displayFiles > 0 ? (
227→            <span className="text-xs text-muted-foreground" data-testid="agent-file-count">
228→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
229→            </span>
230→          ) : undefined}
231→        </div>
232→        <AgentSessionPanel
233→          workspaceId={workspaceId}
234→          agentSessionId={currentSessionId}
235→          sessionStatus={displayStatus}
236→          outputEntries={sessionState.outputEntries}
237→          stallWarning={sessionState.stallWarning}
238→          connectionError={sessionState.connectionError}
239→        />
240→        {displayStatus === "idle" ? (
241→          <a
242→            className="text-xs font-medium text-ring hover:underline"
243→            data-testid="agent-review-link"
244→            href={`/review/${encodeURIComponent(currentSessionId)}`}
245→          >
246→            Review
247→          </a>
248→        ) : undefined}
249→      </div>
250→    );
251→  }
252→
253→  if (initialView.variant === "assign") {
254→    const missingRepoPath = shouldShowRepoPathBanner({
255→      worktreeManagerEnabled: config.worktreeManagerEnabled,
256→      repoPath,
257→    });
258→
259→    return (
260→      <div className="flex flex-col gap-2 px-4">
261→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
262→        {missingRepoPath ? (
263→          <div className="flex flex-col gap-2 rounded-md border border-border bg-muted p-3" data-testid="agent-repo-path-banner">
264→            <p className="text-xs text-muted-foreground">Repository path is not configured for this workspace. Set it before assigning an agent.</p>
265→            <form
266→              className="flex items-center gap-1.5"
267→              data-testid="agent-repo-path-form"
268→              onSubmit={async (e) => {
269→                e.preventDefault();
270→                const trimmed = repoPathInput.trim();
271→                if (!trimmed || settingRepoPath) return;
272→                setSettingRepoPath(true);
273→                setRepoPathError(undefined);
274→                try {
275→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
276→                    method: "POST",
277→                    headers: { "Content-Type": "application/json" },
278→                    body: JSON.stringify({ path: trimmed }),
279→                  });
280→                  if (!res.ok) {
281→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
282→                    setRepoPathError(body.error ?? "Failed to set repository path");
283→                    return;
284→                  }
285→                  setStoreRepoPath(trimmed);
286→                  setRepoPathInput("");
287→                } catch {
288→                  setRepoPathError("Network error");
289→                } finally {
290→                  setSettingRepoPath(false);
291→                }
292→              }}
293→            >
294→              <Input
295→                type="text"
296→                data-testid="agent-repo-path-input"
297→                placeholder="/path/to/git/repository"
298→                value={repoPathInput}
299→                onChange={(e) => setRepoPathInput(e.target.value)}
300→                disabled={settingRepoPath}
301→                className="h-7 flex-1 text-xs"
302→              />
303→              <Button
304→                type="submit"
305→                size="xs"
306→                data-testid="agent-repo-path-action"
307→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
308→              >
309→                {settingRepoPath ? "Setting..." : "Set Path"}
310→              </Button>
311→            </form>
312→            {repoPathError ? (
313→              <p className="text-xs text-destructive" data-testid="agent-repo-path-error">{repoPathError}</p>
314→            ) : undefined}
315→          </div>
316→        ) : undefined}
317→        {agentsLoading ? (
318→          <p className="text-xs text-muted-foreground" data-testid="agent-picker-loading">Loading agents...</p>
319→        ) : assignableAgents.length === 0 ? (
320→          <p className="text-xs text-muted-foreground" data-testid="agent-picker-empty">No agents configured. Create a sandbox or external agent first.</p>
321→        ) : (
322→          <Select value={selectedAgentId ?? ""} onValueChange={(v) => setSelectedAgentId(v ?? undefined)}>
323→            <SelectTrigger className="w-full" data-testid="agent-picker-trigger">
324→              <SelectValue placeholder="Select an agent..." />
325→            </SelectTrigger>
326→            <SelectContent>
327→              {assignableAgents.map((agent) => (
328→                <SelectItem key={agent.id} value={agent.id} data-testid={`agent-picker-option-${agent.id}`}>
329→                  {agent.name} ({agent.runtime})
330→                </SelectItem>
331→              ))}
332→            </SelectContent>
333→          </Select>
334→        )}
335→        <Button
336→          variant="outline"
337→          size="sm"
338→          data-testid="agent-assign-button"
339→          disabled={assigning || missingRepoPath || (assignableAgents.length === 0 && !agentsLoading)}
340→          onClick={handleAssign}
341→        >
342→          {assigning ? "Assigning..." : "Assign Agent"}
343→        </Button>
344→        {assignError ? (
345→          <p className="text-xs text-destructive" data-testid="agent-assign-error">{assignError}</p>
346→        ) : undefined}
347→      </div>
348→    );
349→  }
350→
351→  return undefined;
352→}
