 58→  }
 59→
 60→  if (input.agentSession) {
 61→    return {
 62→      variant: "active",
 63→      agentSessionId: input.agentSession.agentSessionId,
 64→      orchestratorStatus: input.agentSession.orchestratorStatus,
 65→      filesChangedCount: input.agentSession.filesChangedCount,
 66→      streamId: input.agentSession.streamId,
 67→      startedAt: input.agentSession.startedAt,
 68→    };
 69→  }
 70→
 71→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 72→    return { variant: "assign" };
 73→  }
